mapper.select:
SELECT o.*, s.orders_status_name FROM orders o JOIN orders_status s ON o.orders_status_idx = s.orders_status_idx WHERE o.mem_idx = #{mem_idx}
AND ( o.orders_idx::text LIKE '%' || #{searchKeyword} || '%' OR o.orders_idx IN ( SELECT oi.orders_idx FROM orders_item oi JOIN item i ON oi.item_idx = i.item_idx WHERE i.item_name LIKE '%' || #{searchKeyword} || '%' ) )
ORDER BY o.orders_regdate DESC

mapper.update:
UPDATE orders 
SET orders_status_idx = #{param2} 
WHERE orders_idx = #{param1}

mapper.select:
SELECT COUNT(*) 
FROM orders 
WHERE mem_idx = #{mem_idx}
